import React from "react";
import "./index.scss";

export default function Card({
  title,
  description,
  image,
  tags = [], // тепер тут будуть статуси та категорії
  buttonDonateText = "ПІДТРИМАТИ 🍀",
  buttonMoreText = "Детальніше 🔍"
}) {
  return (
    <div className="card">
      <div className="card__image-wrapper">
        <img src={image} className="card__image" alt={title} />
      </div>

      <div className="card__body">
        <h5 className="card__title">{title}</h5>
        <p className="card__description">{description}</p>

        {/* Теги з динамічними класами кольорів */}
        {tags.length > 0 && (
          <div className="card__tags">
            {tags.map((tag, index) => (
              <span 
                key={index} 
                className={`card__badge card__badge--${tag.toLowerCase().replace(/\s+/g, '-')}`}
              >
                {tag}
              </span>
            ))}
          </div>
        )}

        <a href="#" className="card__button_donate">{buttonDonateText}</a>
        <a href="#" className="card__button_more">{buttonMoreText}</a>
      </div>
    </div>
  );
}